// === Diff: which chunk IDs are new, which are stale ===
const newChunks = $('Chunk + Hash').all().map(it => it.json);
const scroll = $input.first().json;

const existingPoints = (scroll && scroll.result && scroll.result.points) || [];
const existingIds = new Set(existingPoints.map(p => String(p.id)));
const newIdSet = new Set(newChunks.map(c => c.pointId));

const toInsert = newChunks.filter(c => !existingIds.has(c.pointId));
const toDeleteIds = existingPoints
  .filter(p => !newIdSet.has(String(p.id)))
  .map(p => p.id);

return [{
  json: {
    summary: {
      totalChunks: newChunks.length,
      newChunks: toInsert.length,
      removedChunks: toDeleteIds.length,
      unchangedChunks: newChunks.length - toInsert.length
    },
    toInsert,
    toDeleteIds,
    versionId: newChunks[0] ? newChunks[0].versionId : null,
    documentUrl: newChunks[0] ? newChunks[0].documentUrl : null,
    documentHash: newChunks[0] ? newChunks[0].documentHash : null
  }
}];

const crypto = require('crypto');

const cfg = $('Set Config').first().json;
const { summary, toInsert, toDeleteIds, versionId, documentUrl, documentHash } = $input.first().json;

function clip(t, max = 600) {
  const s = (t || '').toString().replace(/\s+/g, ' ').trim();
  if (s.length <= max) return s;
  return s.slice(0, max).trimEnd() + '…';
}

const addedSnippets = (toInsert || []).slice(0, 8).map((c, i) => {
  const idx = c.chunkIndex ?? i;
  return `- [chunk ${idx}] ${clip(c.chunkText, 500)}`;
});

const changeSummaryText = [
  `Regulatory change detected for: ${documentUrl}`,
  `Detected at: ${versionId}`,
  `Document hash: ${documentHash}`,
  ``,
  `Summary:`,
  `- New/changed chunks: ${summary.newChunks}`,
  `- Removed chunks: ${summary.removedChunks}`,
  `- Total chunks: ${summary.totalChunks}`,
  ``,
  `New/changed excerpts (sample):`,
  ...(addedSnippets.length ? addedSnippets : ['- (no new excerpts captured)']),
  ``,
  `Removed chunk IDs (count): ${Array.isArray(toDeleteIds) ? toDeleteIds.length : 0}`,
].join('\n');

const idSource = `${documentUrl}::${versionId}::change-log`;
const pointId = crypto.createHash('sha1').update(idSource).digest('hex').slice(0, 32);

return [{
  json: {
    pointId,
    chunkText: changeSummaryText,
    metadata: {
      documentUrl,
      documentHash,
      versionId,
      changes: summary,
    }
  }
}];

// Reuse the Bedrock SigV4 signer logic by delegating to the existing node.
// This node exists so the change-log branch can sign/embed independently.
//
// We intentionally duplicate the signer code here to keep the workflow self-contained.
const crypto = require('crypto');

const cfg = $('Set Config').first().json;
const region = cfg.awsRegion;
const modelId = cfg.embedModelId;

const accessKeyId = $env.N8N_AWS_ACCESS_KEY_ID;
const secretAccessKey = $env.N8N_AWS_SECRET_ACCESS_KEY;
const rawSessionToken = $env.N8N_AWS_SESSION_TOKEN;

function normalizeSessionToken(raw) {
  if (raw == null || typeof raw !== 'string') return '';
  const t = raw.trim();
  if (!t) return '';
  const lower = t.toLowerCase();
  if (lower === 'your_session_token' || lower === 'optional' || lower === 'placeholder' || lower === 'none' || lower === 'null' || lower === 'undefined') return '';
  if (t.length < 50) return '';
  return t;
}

const sessionToken = normalizeSessionToken(rawSessionToken);

if (!accessKeyId || !secretAccessKey) {
  throw new Error('Missing AWS credentials in env.');
}

const host = `bedrock-runtime.${region}.amazonaws.com`;
const service = 'bedrock';
const method = 'POST';
const canonicalUri = `/model/${encodeURIComponent(modelId)}/invoke`;

const body = JSON.stringify({
  inputText: $json.chunkText,
  dimensions: cfg.embedDimensions,
  normalize: true,
});

const sha256Hex = (data) => crypto.createHash('sha256').update(data, 'utf8').digest('hex');
const hmac = (key, msg) => crypto.createHmac('sha256', key).update(msg, 'utf8').digest();

const amzDate = new Date().toISOString().replace(/[:-]|\.\d{3}/g, '');
const dateStamp = amzDate.slice(0, 8);
const payloadHash = sha256Hex(body);

const headersToSign = {
  host,
  'content-type': 'application/json',
  accept: 'application/json',
  'x-amz-date': amzDate,
  'x-amz-content-sha256': payloadHash,
};
if (sessionToken) headersToSign['x-amz-security-token'] = sessionToken;

const signedHeaderNames = Object.keys(headersToSign).map((k) => k.toLowerCase()).sort();
const canonicalHeaders = signedHeaderNames.map((n) => `${n}:${headersToSign[n]}\n`).join('');
const signedHeaders = signedHeaderNames.join(';');

const canonicalRequest = [method, canonicalUri, '', canonicalHeaders, signedHeaders, payloadHash].join('\n');

const algorithm = 'AWS4-HMAC-SHA256';
const credentialScope = `${dateStamp}/${region}/${service}/aws4_request`;
const stringToSign = [algorithm, amzDate, credentialScope, sha256Hex(canonicalRequest)].join('\n');

const kDate = hmac(`AWS4${secretAccessKey}`, dateStamp);
const kRegion = hmac(kDate, region);
const kService = hmac(kRegion, service);
const kSigning = hmac(kService, 'aws4_request');
const signature = crypto.createHmac('sha256', kSigning).update(stringToSign, 'utf8').digest('hex');

const authorization = `${algorithm} Credential=${accessKeyId}/${credentialScope}, SignedHeaders=${signedHeaders}, Signature=${signature}`;

return {
  json: {
    ...$json,
    _signed: {
      headers: { ...headersToSign, authorization },
      body,
    },
  },
};

// Build a Qdrant point for the change-log collection.
// NOTE: $json here is the Bedrock embedding response, so we must pull the
// original change-log fields from the earlier node.
const change = $('Build Change Log Text').first().json;
const embed = $input.first().json;

return [{
  json: {
    point: {
      id: change.pointId,
      vector: embed.embedding,
      payload: {
        content: change.chunkText,
        metadata: change.metadata,
      }
    }
  }
}];

// === Bedrock SigV4 signer (no HTTP) ===
// n8n's HTTP Request node signs Bedrock-Runtime requests with service
// 'bedrock-runtime' (derived from URL host). AWS requires service 'bedrock',
// so it returns 403. We sign here, then a downstream HTTP Request node
// (Authentication: None) forwards the pre-signed request unmodified.
//
// Sandbox-safe: uses only `crypto` (already in NODE_FUNCTION_ALLOW_BUILTIN)
// and `$env` for credentials. Does NOT call fetch / process / this.helpers,
// none of which are exposed in the n8n task-runner VM.
//
// Required env vars on the n8n container:
//   N8N_AWS_ACCESS_KEY_ID       (required)
//   N8N_AWS_SECRET_ACCESS_KEY   (required)
//   N8N_AWS_SESSION_TOKEN       (optional — omit or unset for IAM user keys)
const crypto = require('crypto');

const cfg = $('Set Config').first().json;
const region = cfg.awsRegion;
const modelId = cfg.embedModelId;

const accessKeyId = $env.N8N_AWS_ACCESS_KEY_ID;
const secretAccessKey = $env.N8N_AWS_SECRET_ACCESS_KEY;
const rawSessionToken = $env.N8N_AWS_SESSION_TOKEN;

/** Only send x-amz-security-token for real STS / SSO / assumed-role creds.
 *  Long-term IAM users must omit this header entirely.
 *  Placeholder env values like "your_session_token" cause:
 *    "The security token included in the request is invalid."
 */
function normalizeSessionToken(raw) {
  if (raw == null || typeof raw !== 'string') return '';
  const t = raw.trim();
  if (!t) return '';
  const lower = t.toLowerCase();
  if (
    lower === 'your_session_token' ||
    lower === 'optional' ||
    lower === 'placeholder' ||
    lower === 'none' ||
    lower === 'null' ||
    lower === 'undefined'
  ) {
    return '';
  }
  // Real AWS STS session tokens are typically hundreds of characters.
  if (t.length < 50) return '';
  return t;
}

const sessionToken = normalizeSessionToken(rawSessionToken);

if (!accessKeyId || !secretAccessKey) {
  throw new Error(
    'Missing AWS credentials. Set N8N_AWS_ACCESS_KEY_ID and N8N_AWS_SECRET_ACCESS_KEY ' +
    'as environment variables on the n8n container, then restart it. ' +
    'If $env still returns empty, ensure N8N_BLOCK_ENV_ACCESS_IN_NODE is not true.'
  );
}

const host = `bedrock-runtime.${region}.amazonaws.com`;
const service = 'bedrock';
const method = 'POST';
// The HTTP Request node sends the path with a literal ':' (modelIds like
// 'amazon.titan-embed-text-v2:0'). On the wire that ':' stays literal —
// it's a valid URI pchar — and AWS performs its single canonical-encoding
// pass on receipt, turning ':' into '%3A'. So our signed canonical URI
// must be SINGLE-encoded too.
const canonicalUri = `/model/${encodeURIComponent(modelId)}/invoke`;

const body = JSON.stringify({
  inputText: $json.chunkText,
  dimensions: cfg.embedDimensions,
  normalize: true,
});

const sha256Hex = (data) => crypto.createHash('sha256').update(data, 'utf8').digest('hex');
const hmac = (key, msg) => crypto.createHmac('sha256', key).update(msg, 'utf8').digest();

const amzDate = new Date().toISOString().replace(/[:-]|\.\d{3}/g, '');
const dateStamp = amzDate.slice(0, 8);
const payloadHash = sha256Hex(body);

const headersToSign = {
  host,
  'content-type': 'application/json',
  accept: 'application/json',
  'x-amz-date': amzDate,
  'x-amz-content-sha256': payloadHash,
};
if (sessionToken) headersToSign['x-amz-security-token'] = sessionToken;

const signedHeaderNames = Object.keys(headersToSign).map((k) => k.toLowerCase()).sort();
const canonicalHeaders = signedHeaderNames.map((n) => `${n}:${headersToSign[n]}\n`).join('');
const signedHeaders = signedHeaderNames.join(';');

const canonicalRequest = [
  method,
  canonicalUri,
  '',
  canonicalHeaders,
  signedHeaders,
  payloadHash,
].join('\n');

const algorithm = 'AWS4-HMAC-SHA256';
const credentialScope = `${dateStamp}/${region}/${service}/aws4_request`;
const stringToSign = [
  algorithm,
  amzDate,
  credentialScope,
  sha256Hex(canonicalRequest),
].join('\n');

const kDate = hmac(`AWS4${secretAccessKey}`, dateStamp);
const kRegion = hmac(kDate, region);
const kService = hmac(kRegion, service);
const kSigning = hmac(kService, 'aws4_request');
const signature = crypto.createHmac('sha256', kSigning).update(stringToSign, 'utf8').digest('hex');

const authorization =
  `${algorithm} Credential=${accessKeyId}/${credentialScope}, ` +
  `SignedHeaders=${signedHeaders}, Signature=${signature}`;

// Note: we deliberately do NOT include a `_signed.url` here. The HTTP
// Request node builds its URL directly from Set Config, which keeps the
// node settings readable. Host/path used here for signing must match what
// that node will actually send.
return {
  json: {
    ...$json,
    _signed: {
      headers: { ...headersToSign, authorization },
      body,
    },
  },
};

// Combine the chunk metadata with the embedding into one Qdrant point.
const chunk = $('Split: New Chunks').item.json;
const embed = $input.item.json;

return {
  json: {
    point: {
      id: chunk.pointId,
      vector: embed.embedding,
      payload: {
        content: chunk.chunkText,
        metadata: {
          chunkHash: chunk.chunkHash,
          chunkIndex: chunk.chunkIndex,
          documentUrl: chunk.documentUrl,
          documentHash: chunk.documentHash,
          versionId: chunk.versionId
        }
      }
    }
  }
};

const body = $json.body || $json;
const chatInput = (body.chatInput ?? body.question ?? '').toString();

if (!chatInput.trim()) throw new Error('Missing chatInput');

return [{ json: { chatInput } }];

const raw = $json;

// Common shapes observed from n8n LangChain agent nodes.
const answer = raw.output ?? raw.response ?? raw.text ?? raw.answer ?? raw.result ?? raw;

return [{
  json: {
    answer: typeof answer === 'string' ? answer : JSON.stringify(answer),
  }
}];

