const points = ($input.first().json?.result?.points) || [];

function esc(s) {
  return String(s ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function getMeta(p) {
  const payload = p?.payload || {};
  const meta = payload?.metadata || {};
  const review = meta?.review || {};
  return {
    content: payload?.content || '',
    documentUrl: meta?.documentUrl || '',
    versionId: meta?.versionId || '',
    status: review?.status || 'Pending',
    reviewedAt: review?.at || ''
  };
}

const rows = points
  .map((p) => {
    const id = esc(p.id);
    const m = getMeta(p);
    const content = esc(m.content).slice(0, 1200);
    const doc = esc(m.documentUrl);
    const ver = esc(m.versionId);
    const status = esc(m.status);
    const reviewedAt = esc(m.reviewedAt);

    const actions = status === 'Pending'
      ? `
        <form method="POST" action="/webhook/regulatory-review-action" style="display:inline">
          <input type="hidden" name="id" value="${id}" />
          <input type="hidden" name="action" value="approve" />
          <button type="submit">Approve</button>
        </form>
        <form method="POST" action="/webhook/regulatory-review-action" style="display:inline;margin-left:8px">
          <input type="hidden" name="id" value="${id}" />
          <input type="hidden" name="action" value="dismiss" />
          <button type="submit">Dismiss</button>
        </form>
      `
      : `<span style="color:#666">${status}${reviewedAt ? ` @ ${reviewedAt}` : ''}</span>`;

    return `
      <div style="border:1px solid #e5e7eb;border-radius:10px;padding:12px;margin:12px 0">
        <div style="font-size:12px;color:#6b7280">id: <code>${id}</code></div>
        <div style="margin-top:6px"><b>Document</b>: <a href="${doc}" target="_blank">${doc}</a></div>
        <div><b>Detected at</b>: <code>${ver}</code></div>
        <div><b>Status</b>: <code>${status}</code></div>
        <details style="margin-top:8px">
          <summary>View change excerpt</summary>
          <pre style="white-space:pre-wrap;background:#f9fafb;padding:10px;border-radius:8px;overflow:auto">${content}</pre>
        </details>
        <div style="margin-top:10px">${actions}</div>
      </div>
    `;
  })
  .join('\n');

const html = `<!doctype html>
<html>
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>Regulatory Change Review</title>
</head>
<body style="font-family: ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Arial; max-width: 980px; margin: 24px auto; padding: 0 16px;">
  <h2 style="margin:0">Regulatory Change Review (Phase 3)</h2>
  <p style="color:#6b7280">Review the latest detected changes. Approvals can trigger downstream sync later (SharePoint phase).</p>
  ${rows || '<p><b>No change logs found.</b> Run ingestion with a change to generate entries.</p>'}
</body>
</html>`;

return [{ json: { html } }];

const body = $json.body || $json;
const id = body.id || body?.query?.id;
const action = (body.action || body?.query?.action || '').toString().toLowerCase();

if (!id) throw new Error('Missing id');
if (!['approve','dismiss'].includes(action)) throw new Error('Invalid action');

const status = action === 'approve' ? 'Approved' : 'Dismissed';
const at = new Date().toISOString();

return [{ json: { id: String(id), status, at } }];

